1	import fs from "fs";
2	import path from "path";
3	import yaml from "js-yaml";
4	import type { FeatureStatusYaml, FeatureSummary, FeatureStatus, LifecycleStage } from "@/types/feature";
5	
6	function getFeaturesDir(workspaceRoot: string): string {
7	  return path.join(workspaceRoot, "docs", "features");
8	}
9	
10	export function loadFeatureStatus(workspaceRoot: string, featureId: string): FeatureStatusYaml | null {
11	  const statusPath = path.join(getFeaturesDir(workspaceRoot), featureId, "status.yaml");
12	  if (!fs.existsSync(statusPath)) return null;
13	  try {
14	    const raw = fs.readFileSync(statusPath, "utf-8");
15	    return yaml.load(raw) as FeatureStatusYaml;
16	  } catch {
17	    return null;
18	  }
19	}
20	
21	export function writeFeatureStatus(workspaceRoot: string, featureId: string, data: FeatureStatusYaml): void {
22	  const statusPath = path.join(getFeaturesDir(workspaceRoot), featureId, "status.yaml");
23	  fs.writeFileSync(statusPath, yaml.dump(data, { lineWidth: 120, noRefs: true }), "utf-8");
24	}
25	
26	export async function listFeatures(
27	  workspaceId: string,
28	  workspaceRoot: string,
29	  filters?: { featureStatus?: FeatureStatus; currentStage?: LifecycleStage }
30	): Promise<FeatureSummary[]> {
31	  const featuresDir = getFeaturesDir(workspaceRoot);
32	  if (!fs.existsSync(featuresDir)) return [];
33	
34	  const entries = fs.readdirSync(featuresDir, { withFileTypes: true });
35	  const summaries: FeatureSummary[] = [];
36	
37	  for (const entry of entries) {
38	    if (!entry.isDirectory()) continue;
39	    const featureId = entry.name;
40	    const status = loadFeatureStatus(workspaceRoot, featureId);
41	    if (!status) continue;
42	
43	    if (filters?.featureStatus && status.feature_status !== filters.featureStatus) continue;
44	    if (filters?.currentStage && status.current_stage !== filters.currentStage) continue;
45	
46	    const lastHistoryEntry = status.history[status.history.length - 1];
47	
48	    summaries.push({
49	      featureId,
50	      title: status.title,
51	      featureStatus: status.feature_status,
52	      currentStage: status.current_stage,
53	      nextAction: status.next_action ?? null,
54	      workspaceId,
55	      workspaceRoot,
56	      lastUpdatedAt: lastHistoryEntry?.at ?? null,
57	    });
58	  }
59	
60	  return summaries.sort((a, b) => {
61	    if (!a.lastUpdatedAt) return 1;
62	    if (!b.lastUpdatedAt) return -1;
63	    return b.lastUpdatedAt.localeCompare(a.lastUpdatedAt);
64	  });
65	}
66	
67	export async function getFeatureSummary(
68	  workspaceId: string,
69	  workspaceRoot: string,
70	  featureId: string
71	): Promise<FeatureSummary | null> {
72	  const status = loadFeatureStatus(workspaceRoot, featureId);
73	  if (!status) return null;
74	
75	  const lastHistoryEntry = status.history[status.history.length - 1];
